// bktec fetches and runs test plans generated by Buildkite
// Test Engine.
package main

import (
	"context"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strings"

	"github.com/buildkite/test-engine-client/v2/internal/command"
	"github.com/buildkite/test-engine-client/v2/internal/config"
	"github.com/buildkite/test-engine-client/v2/internal/debug"
	"github.com/buildkite/test-engine-client/v2/internal/git"
	"github.com/buildkite/test-engine-client/v2/internal/testqueue"
	"github.com/buildkite/test-engine-client/v2/internal/version"
	"github.com/urfave/cli/v3"
)

var (
	cfg                         = config.New()
	queueEnvFileNameUnsafeChars = regexp.MustCompile(`[^A-Za-z0-9_.-]+`)
)

func main() {
	if err := cliCommand.Run(context.Background(), os.Args); err != nil {
		logErrorAndExit(err)
	}
}

func run(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Bool("debug"))

	if err := applyPlanRequestContext(cmd); err != nil {
		return err
	}

	if err := cfg.ValidateForRun(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	return command.Run(ctx, &cfg, cmd.String("files"))
}

func plan(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Bool("debug"))
	debug.SetOutput(os.Stderr)

	if err := applyPlanRequestContext(cmd); err != nil {
		return err
	}

	if err := cfg.ValidateForPlan(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	if cmd.Bool("json") {
		return command.Plan(ctx, &cfg, cmd.String("files"), command.PlanOutputJSON, "")
	} else {
		return command.Plan(ctx, &cfg, cmd.String("files"), command.PlanOutputPipelineUpload, cmd.String("pipeline-upload"))
	}
}

func queuePush(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Root().Bool("debug"))

	if err := cfg.ValidateForQueuePush(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	return command.QueuePush(ctx, &cfg, cmd.String("files"), cmd.String("file"))
}

func queueWorker(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Root().Bool("debug"))

	if err := cfg.ValidateForQueueWorker(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	return command.QueueWorker(ctx, &cfg)
}

func queueMetrics(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Root().Bool("debug"))

	if err := cfg.ValidateForQueueMetrics(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	return command.QueueMetrics(ctx, &cfg)
}

func queueEnv(context.Context, *cli.Command) error {
	if err := cfg.ValidateForQueueUUID(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	printQueueNameEnv(cfg.QueueName)
	return nil
}

func queueUUID(context.Context, *cli.Command) error {
	if err := cfg.ValidateForQueueUUID(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	queueUUID, err := testqueue.NewQueueUUID()
	if err != nil {
		return err
	}
	fmt.Printf("export BUILDKITE_TEST_ENGINE_QUEUE_UUID=%s\n", shellQuote(queueUUID))
	printQueueNameEnv(cfg.QueueName)
	return nil
}

func printQueueNameEnv(queueName string) {
	fmt.Printf("export BUILDKITE_TEST_ENGINE_QUEUE_NAME=%s\n", shellQuote(queueName))
	fmt.Printf("export BUILDKITE_TEST_ENGINE_QUEUE_ENV_FILE=%s\n", shellQuote(queueEnvFileName(queueName)))
	fmt.Printf("export BUILDKITE_TEST_ENGINE_QUEUE_METADATA_KEY=%s\n", shellQuote(queueMetadataKey(queueName)))
}

func shellQuote(value string) string {
	return "'" + strings.ReplaceAll(value, "'", "'\\''") + "'"
}

func queueEnvFileName(queueName string) string {
	return "test-engine-queue-" + sanitizedQueueName(queueName) + ".env"
}

func queueMetadataKey(queueName string) string {
	return "test-engine-queue-" + sanitizedQueueName(queueName) + "-env"
}

func sanitizedQueueName(queueName string) string {
	name := strings.Trim(queueEnvFileNameUnsafeChars.ReplaceAllString(queueName, "-"), "-")
	if name == "" {
		name = "tests"
	}
	return name
}

func backfillCommitMetadata(ctx context.Context, cmd *cli.Command) error {
	debug.SetDebug(cmd.Root().Bool("debug"))
	debug.SetOutput(os.Stderr)

	if err := cfg.ValidateForBackfillCommitMetadata(); err != nil {
		return fmt.Errorf("invalid configuration...\n%w", err)
	}

	return command.BackfillCommitMetadata(ctx, &cfg, &git.ExecGitRunner{})
}

func printVersion(ctx context.Context, cmd *cli.Command, versionFlag bool) error {
	// Flag will be true if called with `bktec [...] --version`
	if !versionFlag {
		return nil
	}
	fmt.Printf("bktec %s\n", version.Version)
	os.Exit(0)
	return nil
}

func logErrorAndExit(err error) {
	fmt.Fprintln(os.Stderr, err)

	exitError := new(exec.ExitError)
	if errors.As(err, &exitError) {
		// If error wraps an exitError exit with the specified code ...
		os.Exit(exitError.ExitCode())
	} else {
		// otherwise exit code 16
		os.Exit(16)
	}
}
